+    #[test]
+    fn hpke_sealed_box_from_bytes_accepts_max_sized_input() {
+        let max_input = vec![0u8; HPKE_MAX_CIPHERTEXT];
+        let result = HpkeSealedBox::from_bytes(&max_input).unwrap();
