+        let oversized_input = vec![0u8; HPKE_MAX_CIPHERTEXT + 1];
+        let error = HpkeSealedBox::from_bytes(&oversized_input).unwrap_err();
+
+        assert!(
+            error.to_string().contains("sealed box too large"),
+            "unexpected error: {error}"
+        );
+    }
